-- =============================================================
-- FILE: 006_references.seed.sql
-- Ensotek com.tr - Referanslar (Logolu) — 455 firma
-- Kaynak: ensotek.de (026/027 ensotek_com referans seti) birebir uyarlandi
-- ✅ category_id NULL (com.tr categories FK bagimliligi yok)
-- ✅ sub_category_id kolonu com.tr semasinda yok, atlandi
-- ✅ Cloudinary logo URL'leri (ensotek.de ile ayni gorseller)
-- ✅ TR + EN i18n
-- Bu seed referans tablosunun TEK sahibidir: once temizler, sonra doldurur.
-- =============================================================

SET NAMES utf8mb4;
SET time_zone = '+00:00';
SET FOREIGN_KEY_CHECKS = 0;

START TRANSACTION;

-- Eski referans verisini temizle (idempotent / authoritative)
DELETE FROM `references_i18n`;
DELETE FROM `reference_images_i18n`;
DELETE FROM `reference_images`;
DELETE FROM `references`;

-- =============================================================
-- 1) PARENT: references
-- =============================================================
ON DUPLICATE KEY UPDATE
  is_published = VALUES(is_published),
  is_featured = VALUES(is_featured),
  display_order = VALUES(display_order),
  featured_image = VALUES(featured_image),
  website_url = VALUES(website_url),
  category_id = VALUES(category_id),
  updated_at = VALUES(updated_at);

-- =============================================================
-- 2) I18N: TR
-- =============================================================
ON DUPLICATE KEY UPDATE
  title = VALUES(title), slug = VALUES(slug), summary = VALUES(summary),
  content = VALUES(content), featured_image_alt = VALUES(featured_image_alt),
  meta_title = VALUES(meta_title), meta_description = VALUES(meta_description),
  updated_at = VALUES(updated_at);

-- =============================================================
-- 3) I18N: EN
-- =============================================================
ON DUPLICATE KEY UPDATE
  title = VALUES(title), slug = VALUES(slug), summary = VALUES(summary),
  content = VALUES(content), featured_image_alt = VALUES(featured_image_alt),
  meta_title = VALUES(meta_title), meta_description = VALUES(meta_description),
  updated_at = VALUES(updated_at);

COMMIT;

SET FOREIGN_KEY_CHECKS = 1;

